
﻿import axios from "../../../../../Helpers/FetchCsrfToken";
import { showToast } from '../../../shared/ToastManager';
import { getTaskTypeName } from '../../shared/utils/taskTypeUtils';

class SnippetApiService {
  async request(url, options = {}) {
    try {
      const response = await axios({
        url,
        method: options.method || 'GET',
        data: options.data,
        headers: {
          'Content-Type': 'application/json',
          ...options.headers
        },
        timeout: 300000
      });

      if (typeof response.data === 'string' && response.data.includes('<!DOCTYPE html>')) {
        throw new Error('Server returned HTML instead of JSON. This usually indicates a server error or database connectivity issue.');
      }

      return response.data;
    } catch (error) {
      console.error('API request failed:', error);
      
      if (error.response) {
        const errorMessage = error.response.data?.message || error.response.statusText || 'Server error';
        throw new Error(`Server Error (${error.response.status}): ${errorMessage}`);
      } else if (error.request) {
        throw new Error('Network Error: Unable to connect to server');
      } else {
        throw new Error(error.message || 'Unknown error occurred');
      }
    }
  }

  async getSnippet(id) {
    try {
      const response = await this.request(`/WorkflowTaskDefSnippet/GetSnippetApi?id=${id}`);
      if (response.success) {
        return response.data;
      } else {
        throw new Error(response.message || 'Failed to load snippet');
      }
    } catch (error) {
      console.error('Error loading snippet:', error);
      throw error;
    }
  }

  async saveSnippet(data) {
    try {
      const response = await this.request('/WorkflowTaskDefSnippet/SaveApi', {
        method: 'POST',
        data: data
      });
      return response;
    } catch (error) {
      console.error('Error saving snippet:', error);
      throw error;
    }
  }

  async deleteSnippet(id) {
    try {
      const response = await this.request(`/WorkflowTaskDefSnippet/DeleteApi?id=${id}`, {
        method: 'POST'
      });
      return response;
    } catch (error) {
      console.error('Error deleting snippet:', error);
      throw error;
    }
  }

  async getOptions() {
    try {
      const [categories, subcategories] = await Promise.all([
        this.request('/WorkflowTaskDefSnippet/GetCategoryOptions'),
        this.request('/WorkflowTaskDefSnippet/GetSubcategoryOptions')
      ]);

      return {
        categories: this.transformOptions(categories),
        subcategories: this.transformOptions(subcategories)
      };
    } catch (error) {
      console.error('Error loading options:', error);
      return {
        categories: [],
        subcategories: []
      };
    }
  }

  async getSubcategories(categoryCode) {
    try {
      const subcategories = await this.request(`/WorkflowTaskDefSnippet/GetSubcategoryOptions?categoryCode=${encodeURIComponent(categoryCode)}`);
      return this.transformOptions(subcategories);
    } catch (error) {
      console.error('Error loading subcategories:', error);
      return [];
    }
  }

  async getWorkflowAssociations(snippetId) {
    try {
      const response = await this.request(`/WorkflowTaskDefSnippet/GetWorkflowAssociations?snippetId=${snippetId}`);
      return response;
    } catch (error) {
      console.error('Error loading workflow associations:', error);
      console.error('Error details:', error.response?.data || error.message);
      return [];
    }
  }

  async saveWorkflowAssociations(snippetId, workflowIds) {
    try {
      const response = await this.request('/WorkflowTaskDefSnippet/SaveWorkflowAssociations', {
        method: 'POST',
        data: {
          snippetId,
          workflowIds
        }
      });
      return response;
    } catch (error) {
      console.error('Error saving workflow associations:', error);
      throw error;
    }
  }

  async getSnippetTree(snippetId, onError = null) {
    try {
      const response = await this.request(`/WorkflowTaskDefSnippet/GetSnippetTree?snippetId=${snippetId}`);
      if (response.success) {
        const transformNode = (node) => {
          return {
            ...node,
            title: node.Name,
            children: node.Children ? node.Children.map(transformNode) : [],
            expanded: true,
            id: node.Attributes ? node.Attributes['data-item-id'] : null,
            sectionMenu: node.SectionMenu || []
          };
        };
        
        const transformedData = Array.isArray(response.data) 
          ? response.data.map(transformNode)
          : [transformNode(response.data)];
        
        return transformedData;
      } else {
        showToast.error(response.message || 'Failed to load snippet tree');
        throw new Error(response.message || 'Failed to load snippet tree');
      }
    } catch (error) {
      console.error('Error loading snippet tree:', error);
      
      // Call the error callback if provided
      if (onError && typeof onError === 'function') {
        onError(error.message || 'Failed to load snippet tree');
      }
      
      return [];
    }
  }

  async saveSnippetTree(snippetId, treeData) {
    try {
      const response = await this.request('/WorkflowTaskDefSnippet/SaveSnippetTree', {
        method: 'POST',
        data: {
          snippetId,
          treeData
        }
      });
      return response;
    } catch (error) {
      console.error('Error saving snippet tree:', error);
      throw error;
    }
  }

  async validateName(name, excludeId = null) {
    try {
      const url = excludeId 
        ? `/WorkflowTaskDefSnippet/CheckName?name=${encodeURIComponent(name)}&excludeId=${excludeId}`
        : `/WorkflowTaskDefSnippet/CheckName?name=${encodeURIComponent(name)}`;
      
      const response = await this.request(url);
      return response;
    } catch (error) {
      console.error('Error validating name:', error);
      return false;
    }
  }

  transformOptions(apiOptions, addPlaceholder = true) {
    try {
      if (!Array.isArray(apiOptions)) {
        return addPlaceholder ? [{ value: '', label: '-- Select --' }] : [];
      }

      const transformed = apiOptions
        .filter(option => option != null)
        .map(option => ({
          value: option.value || option.id || option.code || '',
          label: option.text || option.name || option.label || option.value || 'Unknown'
        }));

      if (addPlaceholder) {
        return [{ value: '', label: '-- Select --' }, ...transformed];
      }

      return transformed;
    } catch (error) {
      console.error('Error transforming options:', error);
      return addPlaceholder ? [{ value: '', label: '-- Select --' }] : [];
    }
  }

  async getTaskDetail(snippetId, taskId) {
    try {
      const url = `/WorkflowTaskDefSnippet/GetTaskDetail?snippetId=${snippetId}&id=${taskId}`;
      const response = await this.request(url);
      
      if (!response.success) {
        console.error('API: Task detail request failed:', response.message);
        showToast.error(response.message || 'Failed to load task details');
        return {
          success: false,
          message: response.message || 'Failed to load task details',
          data: null
        };
      }
      
      return response;
    } catch (error) {
      console.error('API: Error getting task detail:', error);
      showToast.error(error.message || 'Failed to load task details');
      return {
        success: false,
        message: error.message || 'Failed to load task details',
        data: null
      };
    }
  }

  async saveTaskDetail(taskData, isTaskSetting = false) {
    try {
      const savingMessage = isTaskSetting ? 'Saving task settings...' : 'Saving task...';
      showToast.info(savingMessage);
      
      const { sanitizeTaskDetailForSave, logSanitization } = await import('../../workflowdefinition/utils/formDataSanitizer');
      const sanitizedData = sanitizeTaskDetailForSave(taskData);

      const response = await this.request('/WorkflowTaskDefSnippet/SaveWorkflowTaskDefApi', {
        method: 'POST',
        data: sanitizedData
      });

      if (response.success) {
        showToast.success('Task saved successfully');
      } else {
        showToast.error(response.message || 'Failed to save task');
      }

      return response;
    } catch (error) {
      console.error('Error saving task detail:', error);
      showToast.error(error.message || 'Failed to save task');
      throw error;
    }
  }

  async getSnippets(workflowId) {
    try {
      const response = await this.request(`/WorkflowDef/GetSnippets?workflowId=${workflowId}`);
      return response.data || [];
    } catch (error) {
      console.error('Error loading snippets:', error);
      throw error;
    }
  }

  async insertSnippet(workflowId, taskId, snippetId) {
    try {
      const response = await this.request(`/WorkflowDef/SaveInsertSnippet`, {
        method: 'POST',
        data: {
          snippetId,
          containerId: workflowId,
          currentTaskId: taskId
        }
      });
      return response;
    } catch (error) {
      console.error('Error inserting snippet:', error);
      throw error;
    }
  }

  async getPreconditionForm(snippetId, taskId) {
    try {
      const response = await this.request(`/WorkflowTaskDefSnippet/EditWorkflowTaskDefPreconditions?snippetId=${snippetId}&taskId=${taskId}`);
      return response;
    } catch (error) {
      console.error('Error loading precondition form:', error);
      throw error;
    }
  }

  async savePreconditions(snippetId, taskId, data) {
    try {
      const response = await this.request('/WorkflowTaskDefSnippet/SavePreconditions', {
        method: 'POST',
        data: {
          snippetId,
          taskId,
          ...data
        }
      });
      return response;
    } catch (error) {
      console.error('Error saving preconditions:', error);
      throw error;
    }
  }


  async removeTask(snippetId, taskId) {
    try {
      const response = await this.request('/WorkflowTaskDefSnippet/RemoveWorkflowTaskDef', {
        method: 'POST',
        data: {
          workflowDefId: snippetId,
          id: taskId
        },
        headers: {
          'X-Requested-With': 'XMLHttpRequest'
        }
      });
      // Ensure we have a valid response
      if (response && typeof response === 'object') {
        return response;
      }
      
      // If response is not an object, it might be HTML (shouldn't happen with the fix)
      throw new Error('Invalid response format from server');
    } catch (error) {
      console.error('Error removing task:', error);
      throw error;
    }
  }

  async moveTask(snippetId, taskId, isUp) {
    try {
      const response = await this.request('/WorkflowTaskDefSnippet/MoveWorkflowTaskDefApi', {
        method: 'POST',
        data: {
          workflowDefId: snippetId,
          id: taskId,
          isUp: isUp
        }
      });
      return response;
    } catch (error) {
      console.error('Error moving task:', error);
      throw error;
    }
  }

  async moveTaskToSection(snippetId, taskId, targetSectionId) {
    try {
      const response = await this.request('/WorkflowTaskDefSnippet/MoveWorkflowTaskDefToSectionApi', {
        method: 'POST',
        data: {
          workflowDefId: snippetId,
          sourceId: taskId,
          targetId: targetSectionId
        }
      });
      return response;
    } catch (error) {
      console.error('Error moving task to section:', error);
      throw error;
    }
  }

  async addTask(snippetId, parentTaskId, taskType) {
    try {
      const taskTypeName = getTaskTypeName(taskType);
      showToast.info(`Creating ${taskTypeName} task...`);
      
      const response = await this.request(`/WorkflowTaskDefSnippet/CreateWorkflowTaskDef`, {
        method: 'POST',
        data: {
          snippetId,
          parentTaskId,
          taskType
        }
      });

      if (response.success) {
        showToast.success(response.message || `${taskTypeName} task created successfully`);
      } else {
        showToast.error(response.message || 'Failed to add task');
      }
      
      return {
        ...response,
        taskId: response.data?.taskId || response.taskId
      };
    } catch (error) {
      console.error('Error adding task:', error);
      showToast.error(error.message || `Failed to create ${getTaskTypeName(taskType)} task`);
      throw error;
    }
  }

  async restoreTask(snippetId, taskId) {
    try {
      showToast.info('Restoring task...');
      
      const response = await this.request(`/WorkflowTaskDefSnippet/RestoreWorkflowTaskDef`, {
        method: 'POST',
        data: {
          snippetId,
          taskId
        }
      });

      if (response.success) {
        showToast.success(response.message || 'Task restored successfully');
        return {
          success: true,
          message: response.message || 'Task restored successfully'
        };
      } else {
        showToast.error(response.message || 'Failed to restore task');
        throw new Error(response.message || 'Failed to restore task');
      }
    } catch (error) {
      console.error('Error restoring task:', error);
      showToast.error(error.message || 'Failed to restore task');
      throw error;
    }
  }

  async getTaskPredecessors(snippetId, taskId) {
    try {
      const snippetIdNum = typeof snippetId === 'string' ? parseInt(snippetId, 10) : snippetId;
      const taskIdNum = typeof taskId === 'string' ? parseInt(taskId, 10) : taskId;
      
      if (isNaN(snippetIdNum) || isNaN(taskIdNum) || snippetIdNum === 0 || taskIdNum === 0) {
        throw new Error('Invalid snippet ID or task ID');
      }
      
      const response = await this.request(`/WorkflowTaskDefSnippet/GetTaskPredecessors?snippetId=${snippetIdNum}&taskId=${taskIdNum}`);
      
      if (response.success && Array.isArray(response.data)) {
        return response.data;
      }
      
      return [];
    } catch (error) {
      console.error('Error getting predecessors:', error);
      return [];
    }
  }

  async saveTaskPredecessors(snippetId, taskId, finalPredecessorIds) {
    try {
      showToast.info('Saving predecessors...');
      
      // Ensure snippetId and taskId are numbers
      const snippetIdNum = typeof snippetId === 'string' ? parseInt(snippetId, 10) : snippetId;
      const taskIdNum = typeof taskId === 'string' ? parseInt(taskId, 10) : taskId;
      
      if (isNaN(snippetIdNum) || isNaN(taskIdNum) || snippetIdNum === 0 || taskIdNum === 0) {
        throw new Error('Invalid snippet ID or task ID');
      }
      
      // Convert IDs to numbers
      const predecessorIdsArray = Array.isArray(finalPredecessorIds) ? finalPredecessorIds : [];
      const predecessorIdsNums = predecessorIdsArray.map(id => typeof id === 'string' ? parseInt(id, 10) : id);
      
      // Send simple list of predecessor IDs to backend using axios directly
      const response = await axios({
        url: '/WorkflowTaskDefSnippet/SetTaskPredecessors',
        method: 'POST',
        data: {
          snippetId: snippetIdNum,
          taskId: taskIdNum,
          predecessorIds: predecessorIdsNums
        },
        headers: {
          'Content-Type': 'application/json'
        }
      });

      // Check if response contains HTML (server error)
      if (typeof response.data === 'string' && response.data.includes('<!DOCTYPE html>')) {
        throw new Error('Server returned HTML instead of JSON. This usually indicates a server error or database connectivity issue.');
      }

      const responseData = response.data;

      if (responseData.success) {
        showToast.success('Predecessors saved successfully');
        return {
          success: true,
          message: responseData.message || 'Predecessors saved successfully'
        };
      } else {
        showToast.error(responseData.message || 'Failed to save predecessors');
        throw new Error(responseData.message || 'Failed to save predecessors');
      }
    } catch (error) {
      console.error('Error saving predecessors:', error);
      
      // Handle axios error responses
      if (error.response) {
        const errorMessage = error.response.data?.message || error.response.statusText || 'Server error';
        showToast.error(`Server Error (${error.response.status}): ${errorMessage}`);
        throw new Error(`Server Error (${error.response.status}): ${errorMessage}`);
      } else if (error.request) {
        showToast.error('Network Error: Unable to connect to server');
        throw new Error('Network Error: Unable to connect to server');
      } else {
        showToast.error(error.message || 'Failed to save predecessors');
        throw error;
      }
    }
  }

  async updateSnippetTreeStructure(snippetId, nodeId, parentId, index) {
    try {
      const response = await this.request(`/WorkflowTaskDefSnippet/UpdateTreeStructure`, {
        method: 'POST',
        data: {
          snippetId,
          nodeId,
          parentId,
          index
        }
      });

      return response;
    } catch (error) {
      console.error('Error updating tree structure:', error);
      throw error;
    }
  }

  async cancelTask(snippetId, taskId, deleteTaskDef = false) {
    try {
      const response = await this.request(`/WorkflowTaskDefSnippet/CancelWorkflowTaskDef`, {
        method: 'POST',
        data: {
          snippetId,
          taskId,
          deleteTaskDef
        }
      });

      if (response.success !== false) {
        if (deleteTaskDef) {
          return {
            success: true,
            message: 'Task deleted successfully'
          };
        } else {
          return {
            success: true,
            message: 'Task cancelled successfully'
          };
        }
      } else {
        throw new Error(response.message || 'Failed to cancel task');
      }
    } catch (error) {
      console.error('Error cancelling task:', error);
      throw error;
    }
  }

  async searchUDFs(snippetId, searchTerm) {
    try {
      const response = await this.request(`/WorkflowTaskDefSnippet/SearchUDFs`, {
        method: 'POST',
        data: {
          snippetId,
          searchTerm
        }
      });

      return response;
    } catch (error) {
      console.error('Error searching UDFs:', error);
      throw error;
    }
  }

  async getAnswersForForm(formId, workflowTaskDefId, snippetId, definitionType = 'Snippet') {
    try {
      const response = await this.request(`/WorkflowTaskDefSnippet/GetAnswersForForm`, {
        method: 'POST',
        data: {
          formId,
          workflowTaskDefId,
          snippetId,
          definitionType
        }
      });

      // response is already parsed JSON from axios, not a fetch response
      if (!response.success) {
        showToast.error(response.message || 'Failed to get form answers');
        throw new Error(response.message || 'Failed to get form answers');
      }

      return response;
    } catch (error) {
      console.error('Error getting form answers:', error);
      throw error;
    }
  }


}

export const snippetApi = new SnippetApiService();
